+fn has_trapped_scc(adjacency: &[Vec<usize>]) -> bool {
+    struct Tarjan<'a> {
+        adjacency: &'a [Vec<usize>],
+        index: usize,
+        stack: Vec<usize>,
+        on_stack: Vec<bool>,
+        indices: Vec<Option<usize>>,
+        lowlink: Vec<usize>,
+        trapped: bool,
+    }
+
+    impl Tarjan<'_> {
+        fn strongconnect(&mut self, v: usize) {
+            self.indices[v] = Some(self.index);
+            self.lowlink[v] = self.index;
+            self.index += 1;
+            self.stack.push(v);
+            self.on_stack[v] = true;
+
+            for &w in &self.adjacency[v] {
+                if self.indices[w].is_none() {
+                    self.strongconnect(w);
+                    self.lowlink[v] = self.lowlink[v].min(self.lowlink[w]);
+                } else if self.on_stack[w] {
+                    self.lowlink[v] = self.lowlink[v].min(self.indices[w].unwrap_or(usize::MAX));
+                }
+            }
+
+            if self.lowlink[v] == self.indices[v].unwrap_or(usize::MAX) {
+                let mut component = Vec::new();
+                while let Some(w) = self.stack.pop() {
+                    self.on_stack[w] = false;
+                    component.push(w);
+                    if w == v {
+                        break;
+                    }
+                }
+
+                let cyclic = component.len() > 1
+                    || component
+                        .first()
+                        .is_some_and(|n| self.adjacency[*n].contains(n));
+                if cyclic {
+                    let component_set: BTreeSet<usize> = component.iter().copied().collect();
+                    let mut has_egress = false;
+                    for &u in &component {
+                        if self.adjacency[u].iter().any(|v| !component_set.contains(v)) {
+                            has_egress = true;
+                            break;
+                        }
+                    }
+                    if !has_egress {
+                        self.trapped = true;
+                    }
+                }
+            }
+        }
+    }
+
+    let n = adjacency.len();
+    let mut tarjan = Tarjan {
+        adjacency,
+        index: 0,
+        stack: Vec::new(),
+        on_stack: vec![false; n],
+        indices: vec![None; n],
+        lowlink: vec![0; n],
+        trapped: false,
+    };
+
+    for v in 0..n {
+        if tarjan.indices[v].is_none() {
+            tarjan.strongconnect(v);
+            if tarjan.trapped {
+                return true;
+            }
+        }
+    }
+
+    false
+}
